"use client";

import {
  memo,
  useEffect,
  useId,
  useImperativeHandle,
  useMemo,
  useRef,
} from "react";
import useEmblaCarousel from "embla-carousel-react";
import { cn } from "@/lib/utils";
import {
  DEFAULT_STORY_RAIL_LABELS,
  type StoryRail01Handle,
  type StoryRail01Labels,
  type StoryRail01Props,
  type StoryRailItem,
} from "./types";
import { useStoryRailState } from "./hooks/use-story-rail-state";
import { StoryThumbnail } from "./parts/story-thumbnail";

interface StoryRail01InnerProps extends StoryRail01Props {
  ref?: React.Ref<StoryRail01Handle>;
}

function StoryRail01Inner(props: StoryRail01InnerProps) {
  const {
    items: initialItems,
    leading,
    framed = true,
    subscribe,
    onSubscribeDelta,
    onItemClick,
    linkComponent,
    getHref,
    renderThumbnail,
    emptyState,
    labels: labelsProp,
    className,
    thumbnailClassName,
    ref,
  } = props;

  const labels = useMemo<
    Required<Omit<StoryRail01Labels, "thumbnailAriaLabel">> & {
      thumbnailAriaLabel?: (item: StoryRailItem) => string;
    }
  >(
    () => ({
      ...DEFAULT_STORY_RAIL_LABELS,
      ...labelsProp,
    }),
    [labelsProp],
  );

  const { items, dispatch } = useStoryRailState({
    initialItems,
    subscribe,
    onSubscribeDelta,
  });

  const emblaOptions = useMemo(
    () => ({
      align: "start" as const,
      containScroll: "trimSnaps" as const,
      dragFree: true,
    }),
    [],
  );
  const [emblaRef, emblaApi] = useEmblaCarousel(emblaOptions);

  // Stable ref for the imperative handle.
  const itemsRef = useRef<StoryRailItem[]>(items);
  useEffect(() => {
    itemsRef.current = items;
  });

  useImperativeHandle(
    ref,
    () => ({
      scrollTo: (index: number) => {
        emblaApi?.scrollTo(index);
      },
      getCurrentItems: () => itemsRef.current,
      reset: (next: StoryRailItem[]) => dispatch({ kind: "reset", next }),
      dispatch,
      markViewed: (itemId: string) =>
        dispatch({ kind: "viewed", itemId }),
    }),
    [emblaApi, dispatch],
  );

  const rootId = useId();
  const showEmpty = items.length === 0 && !subscribe && !leading;
  const showRail = !showEmpty;

  return (
    <section
      role="region"
      aria-label={labels.railLabel}
      className={cn(
        "relative overflow-hidden",
        framed ? "rounded-xl border border-border/50 bg-card p-4" : "",
        className,
      )}
    >
      {showRail ? (
        <>
          {/* Edge fade gradients render only when items are present (Q-P22). */}
          <div
            aria-hidden="true"
            className={cn(
              "pointer-events-none absolute inset-y-0 z-10 w-12 bg-linear-to-r to-transparent",
              framed ? "left-4 from-card" : "left-0 from-background",
            )}
          />
          <div
            aria-hidden="true"
            className={cn(
              "pointer-events-none absolute inset-y-0 z-10 w-12 bg-linear-to-l to-transparent",
              framed ? "right-4 from-card" : "right-0 from-background",
            )}
          />
          <div className="overflow-hidden" ref={emblaRef}>
            <div className="flex gap-3 px-2">
              {leading ? <div className="shrink-0">{leading}</div> : null}
              {items.map((item, index) => (
                <div key={item.id} className="shrink-0">
                  {renderThumbnail
                    ? renderThumbnail(item, !!item.hasUnread, {
                        index,
                        onClick: () => onItemClick?.(item, index),
                        baseId: `${rootId}-${item.id}`,
                      })
                    : (
                        <StoryThumbnail
                          item={item}
                          index={index}
                          baseId={`${rootId}-${item.id}`}
                          onItemClick={onItemClick}
                          getHref={getHref}
                          linkComponent={linkComponent}
                          labels={labels}
                          className={thumbnailClassName}
                        />
                      )}
                </div>
              ))}
            </div>
          </div>
        </>
      ) : (
        emptyState ?? (
          <p
            role="status"
            className="py-6 text-center text-sm text-muted-foreground"
          >
            {labels.emptyState}
          </p>
        )
      )}
    </section>
  );
}

const StoryRail01 = memo(StoryRail01Inner);
StoryRail01.displayName = "StoryRail01";

export { StoryRail01 };

export { StoryRail01 } from "./story-rail-01";
export { AddStoryThumbnail } from "./parts/add-story-thumbnail";
export type { AddStoryThumbnailProps } from "./parts/add-story-thumbnail";

export {
  storyRailReducer,
  useStoryRailState,
  type UseStoryRailStateOptions,
  type UseStoryRailStateResult,
} from "./hooks/use-story-rail-state";

export type {
  StoryRailItem,
  StoryRail01Props,
  StoryRail01Handle,
  StoryRail01Labels,
  StoryRailDelta,
  StoryRailLocalAction,
  ThumbnailRenderHelpers,
  Subscribe,
  Unsubscribe,
} from "./types";

export { DEFAULT_STORY_RAIL_LABELS } from "./types";

export { meta } from "./meta";

import type { ElementType, ReactNode } from "react";

export interface StoryRailItem {
  id: string;
  username: string;
  avatar?: string;
  /** Rectangular preview shown inside the gradient/muted ring. */
  previewImage: string;
  /** Drives ring visual: gradient (unread) vs muted (read). Default false. */
  hasUnread?: boolean;
  /** Optional — exposed for downstream story-viewer-01 wiring. */
  userId?: string;
}

export type StoryRailDelta =
  | { kind: "added"; item: StoryRailItem; position?: "start" | "end" }
  | { kind: "removed"; itemId: string }
  | { kind: "viewed"; itemId: string }
  | {
      kind: "updated";
      itemId: string;
      partial: Partial<StoryRailItem>;
    };

export type Unsubscribe = () => void;
export type Subscribe<T> = (handler: (delta: T) => void) => Unsubscribe;

export interface StoryRail01Labels {
  /** Default "Stories". aria-label on the rail's <section role="region">. */
  railLabel?: string;
  /** Default "Add story". Visible label below the AddStoryThumbnail. */
  addStoryLabel?: string;
  /** Default "Add a story". aria-label for the AddStoryThumbnail button. */
  addStoryAriaLabel?: string;
  /** Function so hosts can pluralize / localize. Default returns "{username}, unread story" / "{username}, viewed". */
  thumbnailAriaLabel?: (item: StoryRailItem) => string;
  /** Default "No stories yet." Renders when items.length === 0 AND no leading AND no realtime. */
  emptyState?: string;
}

export const DEFAULT_STORY_RAIL_LABELS: Required<
  Omit<StoryRail01Labels, "thumbnailAriaLabel">
> = {
  railLabel: "Stories",
  addStoryLabel: "Add story",
  addStoryAriaLabel: "Add a story",
  emptyState: "No stories yet.",
};

export type StoryRailLocalAction =
  | { kind: "add"; item: StoryRailItem; position?: "start" | "end" }
  | { kind: "remove"; itemId: string }
  | { kind: "viewed"; itemId: string }
  | { kind: "update"; itemId: string; partial: Partial<StoryRailItem> }
  | { kind: "subscribe-delta"; delta: StoryRailDelta }
  | { kind: "reset"; next: StoryRailItem[] };

export interface ThumbnailRenderHelpers {
  index: number;
  onClick: () => void;
  /** Stable id for ARIA wiring inside the slot. */
  baseId: string;
}

export interface StoryRail01Props {
  /** Items rendered in the rail. Mount-only initial state — use ref.current.reset() to push updates. */
  items: StoryRailItem[];

  /** Optional content rendered before items (typically <AddStoryThumbnail>). */
  leading?: ReactNode;

  /** Wrap the rail in card-style chrome (bg-card + border + rounded). Default true. */
  framed?: boolean;

  /** Realtime delta stream. Identity-stable required (useCallback host-side). */
  subscribe?: Subscribe<StoryRailDelta>;
  onSubscribeDelta?: (delta: StoryRailDelta) => void;

  /** Click handler. Host typically opens a story viewer. */
  onItemClick?: (item: StoryRailItem, index: number) => void;

  /** Polymorphic root for the thumbnail when getHref provided. Default `"a"`. */
  linkComponent?: ElementType;
  /** When provided, thumbnail renders as `<linkComponent href={getHref(item)}>` instead of `<button>`. Click also fires onItemClick if both wired. */
  getHref?: (item: StoryRailItem) => string;

  /** Full-takeover render slot for the thumbnail visual. */
  renderThumbnail?: (
    item: StoryRailItem,
    isUnread: boolean,
    helpers: ThumbnailRenderHelpers,
  ) => ReactNode;

  /** Empty-state slot. Wins over labels.emptyState fallback. */
  emptyState?: ReactNode;

  labels?: StoryRail01Labels;

  className?: string;
  thumbnailClassName?: string;

  ref?: React.Ref<StoryRail01Handle>;
}

export interface StoryRail01Handle {
  scrollTo: (index: number) => void;
  getCurrentItems: () => StoryRailItem[];
  reset: (next: StoryRailItem[]) => void;
  dispatch: (action: StoryRailLocalAction) => void;
  /** Mark a story as viewed (sets hasUnread=false). Call from your viewer's onClose. */
  markViewed: (itemId: string) => void;
}

"use client";

import { memo, type ElementType } from "react";
import { cn } from "@/lib/utils";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import type { StoryRail01Labels, StoryRailItem } from "../types";

export interface StoryThumbnailProps {
  item: StoryRailItem;
  index: number;
  baseId: string;
  onItemClick?: (item: StoryRailItem, index: number) => void;
  getHref?: (item: StoryRailItem) => string;
  linkComponent?: ElementType;
  labels: Required<Omit<StoryRail01Labels, "thumbnailAriaLabel">> & {
    thumbnailAriaLabel?: (item: StoryRailItem) => string;
  };
  className?: string;
}

function initials(name: string): string {
  return (
    name
      .trim()
      .split(/\s+/)
      .map((p) => p[0]?.toUpperCase() ?? "")
      .slice(0, 2)
      .join("") || "?"
  );
}

function defaultAriaLabel(item: StoryRailItem): string {
  return `${item.username}, ${item.hasUnread ? "unread story" : "viewed"}`;
}

function StoryThumbnailInner({
  item,
  index,
  baseId,
  onItemClick,
  getHref,
  linkComponent,
  labels,
  className,
}: StoryThumbnailProps) {
  const isUnread = !!item.hasUnread;
  const ariaLabel = (labels.thumbnailAriaLabel ?? defaultAriaLabel)(item);
  const hasLink = !!getHref;
  const href = hasLink ? getHref!(item) : undefined;
  const handleClick = () => onItemClick?.(item, index);

  const inner = (
    <>
      <div
        className={cn(
          "rounded-2xl p-0.5 transition-all",
          isUnread
            ? "bg-linear-to-br from-accent via-warning to-destructive"
            : "bg-muted",
        )}
      >
        <div className="h-28 w-20 overflow-hidden rounded-[14px] border-2 border-card bg-card">
          <img
            src={item.previewImage}
            alt=""
            className="h-full w-full object-cover transition-transform duration-300 motion-safe:group-hover:scale-105"
          />
        </div>
      </div>
      <div className="flex items-center gap-1.5">
        <Avatar className="h-5 w-5 border border-card">
          {item.avatar ? <AvatarImage src={item.avatar} alt="" /> : null}
          <AvatarFallback className="text-[8px]">
            {initials(item.username)}
          </AvatarFallback>
        </Avatar>
        <span
          id={`${baseId}-name`}
          className="max-w-14 truncate text-center text-xs font-medium"
        >
          {item.username}
        </span>
      </div>
    </>
  );

  if (hasLink && href) {
    const LinkComponent = linkComponent ?? "a";
    return (
      <LinkComponent
        href={href}
        onClick={onItemClick ? handleClick : undefined}
        aria-label={ariaLabel}
        className={cn(
          "group flex shrink-0 flex-col items-center gap-2 focus:outline-none focus-visible:ring-2 focus-visible:ring-ring rounded-2xl",
          className,
        )}
      >
        {inner}
      </LinkComponent>
    );
  }

  return (
    <button
      type="button"
      onClick={handleClick}
      aria-label={ariaLabel}
      className={cn(
        "group flex shrink-0 flex-col items-center gap-2 focus:outline-none focus-visible:ring-2 focus-visible:ring-ring rounded-2xl",
        className,
      )}
    >
      {inner}
    </button>
  );
}

export const StoryThumbnail = memo(StoryThumbnailInner);
StoryThumbnail.displayName = "StoryThumbnail";

"use client";

import { memo } from "react";
import { Plus } from "lucide-react";
import { cn } from "@/lib/utils";

export interface AddStoryThumbnailProps {
  /** Avatar shown at 50% opacity inside the dashed-border placeholder. */
  userAvatar?: string;
  onClick?: () => void;
  /** Visible label below. Default "Add story". */
  label?: string;
  /** aria-label on the button. Default "Add a story". */
  ariaLabel?: string;
  className?: string;
}

function AddStoryThumbnailInner({
  userAvatar,
  onClick,
  label = "Add story",
  ariaLabel = "Add a story",
  className,
}: AddStoryThumbnailProps) {
  return (
    <button
      type="button"
      onClick={onClick}
      aria-label={ariaLabel}
      className={cn(
        "group flex shrink-0 flex-col items-center gap-2",
        className,
      )}
    >
      <div className="relative">
        <div className="h-28 w-20 overflow-hidden rounded-2xl border-2 border-dashed border-muted-foreground/30 bg-muted/50 transition-colors group-hover:border-primary/50">
          {userAvatar ? (
            <img
              src={userAvatar}
              alt=""
              className="h-full w-full object-cover opacity-50"
            />
          ) : (
            <div
              className="h-full w-full bg-muted"
              aria-hidden="true"
            />
          )}
        </div>
        <span
          aria-hidden="true"
          className="absolute bottom-1 right-1 flex h-6 w-6 items-center justify-center rounded-full border-2 border-card bg-primary text-primary-foreground shadow-md"
        >
          <Plus className="h-3.5 w-3.5" />
        </span>
      </div>
      <span className="w-20 truncate text-center text-xs font-medium text-muted-foreground">
        {label}
      </span>
    </button>
  );
}

export const AddStoryThumbnail = memo(AddStoryThumbnailInner);
AddStoryThumbnail.displayName = "AddStoryThumbnail";

"use client";

import { useEffect, useReducer, useRef } from "react";
import type {
  StoryRailDelta,
  StoryRailItem,
  StoryRailLocalAction,
  Subscribe,
} from "../types";

// ─── Pure helpers ────────────────────────────────────────────────────────────

function insertAtPosition(
  state: StoryRailItem[],
  item: StoryRailItem,
  position: "start" | "end" | undefined,
): StoryRailItem[] {
  if (position === "end") return [...state, item];
  return [item, ...state]; // default "start"
}

function removeById(state: StoryRailItem[], id: string): StoryRailItem[] {
  const next = state.filter((i) => i.id !== id);
  return next.length === state.length ? state : next;
}

function patchById(
  state: StoryRailItem[],
  id: string,
  patch: Partial<StoryRailItem>,
): StoryRailItem[] {
  let mutated = false;
  const next = state.map((i) => {
    if (i.id !== id) return i;
    mutated = true;
    return { ...i, ...patch };
  });
  return mutated ? next : state;
}

// ─── Reducer ─────────────────────────────────────────────────────────────────

/** Pure reducer — exported for hosts driving their own state. */
export function storyRailReducer(
  state: StoryRailItem[],
  action: StoryRailLocalAction,
): StoryRailItem[] {
  switch (action.kind) {
    case "add":
      return insertAtPosition(state, action.item, action.position);
    case "remove":
      return removeById(state, action.itemId);
    case "viewed":
      return patchById(state, action.itemId, { hasUnread: false });
    case "update":
      return patchById(state, action.itemId, action.partial);
    case "subscribe-delta": {
      const d = action.delta;
      switch (d.kind) {
        case "added":
          return insertAtPosition(state, d.item, d.position);
        case "removed":
          return removeById(state, d.itemId);
        case "viewed":
          return patchById(state, d.itemId, { hasUnread: false });
        case "updated":
          return patchById(state, d.itemId, d.partial);
      }
      return state;
    }
    case "reset":
      return action.next;
  }
}

// ─── Hook ────────────────────────────────────────────────────────────────────

export interface UseStoryRailStateOptions {
  /** Captured ON MOUNT only — subsequent prop changes are ignored. */
  initialItems: StoryRailItem[];
  subscribe?: Subscribe<StoryRailDelta>;
  onSubscribeDelta?: (delta: StoryRailDelta) => void;
}

export interface UseStoryRailStateResult {
  items: StoryRailItem[];
  dispatch: React.Dispatch<StoryRailLocalAction>;
}

export function useStoryRailState(
  opts: UseStoryRailStateOptions,
): UseStoryRailStateResult {
  const [items, dispatch] = useReducer(storyRailReducer, opts.initialItems);

  const onSubscribeDeltaRef = useRef(opts.onSubscribeDelta);
  useEffect(() => {
    onSubscribeDeltaRef.current = opts.onSubscribeDelta;
  });

  const subscribe = opts.subscribe;
  useEffect(() => {
    if (!subscribe) return;
    const unsub = subscribe((delta) => {
      onSubscribeDeltaRef.current?.(delta);
      dispatch({ kind: "subscribe-delta", delta });
    });
    return unsub;
  }, [subscribe]);

  return { items, dispatch };
}
